/**
 * @fileoverview GridTable Feature — AJAX pagination mixin.
 *
 * Lazy-loaded when `ajax: {...}` is set in config.
 * Adds server-side data fetching, page navigation, and pagination footer.
 *
 * @module module/GridTable/features/pagination
 */

import razyui from '../../../index.js';
import { AJAX_DEFAULTS, MAX_PAGE_BUTTONS, AJAX_DEBOUNCE_MS } from '../constants.js';
import { renderFooter } from '../view.js';
import { bindFooterEvents } from '../events.js';

/**
 * Install the pagination feature onto a GridTable ctx bridge.
 *
 * @param {object} ctx — the shared context bridge
 */
export function installPagination(ctx) {
    ctx._paginationInstalled = true;

    // Merge AJAX config
    const ajaxConfig = Object.assign({ ...AJAX_DEFAULTS }, ctx.config.ajax);
    ctx.ajax = ajaxConfig;
    ctx.ajaxPage = 1;

    // Build footer DOM
    renderFooter(ctx);
    bindFooterEvents(ctx);

    // AJAX debounce timer
    let ajaxDebounce = null;

    /**
     * Fetch data from the AJAX endpoint.
     */
    ctx.ajaxFetch = () => {
        if (!ctx.ajax || ctx._ajaxLoading) return;
        ctx._ajaxLoading = true;
        ctx.container.addClass('is-ajax-loading');
        const cfg = ctx.ajax;
        const params = {
            page:     ctx.ajaxPage,
            pageSize: cfg.pageSize,
            sort:     ctx.sortState
                ? { column: ctx.sortState.column, direction: ctx.sortState.direction }
                : null,
            filters:  { ...ctx.filterValues },
        };
        if (razyui.isFn(cfg.onBeforeRequest)) {
            const modified = cfg.onBeforeRequest(params);
            if (modified) Object.assign(params, modified);
        }
        const url = new URL(cfg.url, location.href);
        url.searchParams.set('page', params.page);
        url.searchParams.set('pageSize', params.pageSize);
        if (params.sort) {
            url.searchParams.set('sortColumn', params.sort.column);
            url.searchParams.set('sortDirection', params.sort.direction);
        }
        for (const [k, v] of Object.entries(params.filters)) {
            if (v) url.searchParams.set('filter_' + k, v);
        }
        fetch(url.toString(), { method: cfg.method })
            .then(r => r.json())
            .then(result => {
                ctx._ajaxLoading = false;
                ctx.container.removeClass('is-ajax-loading');
                let data, total;
                if (razyui.isFn(cfg.onResponse)) {
                    const parsed = cfg.onResponse(result);
                    data = parsed.data;
                    total = parsed.total;
                } else {
                    data = cfg.dataKey ? result[cfg.dataKey] : result;
                    total = cfg.totalKey
                        ? result[cfg.totalKey]
                        : (Array.isArray(data) ? data.length : 0);
                }
                ctx.ajaxTotal = total;
                ctx._setData(data);
                renderFooter(ctx);
            })
            .catch(err => {
                ctx._ajaxLoading = false;
                ctx.container.removeClass('is-ajax-loading');
                // Display error message inside the table
                if (ctx.emptyMsg) {
                    const msg = (err && err.message) ? err.message : 'Failed to load data';
                    ctx.emptyMsg.text(msg).addClass('is-error').css('display', '');
                }
                if (razyui.isFn(cfg.onError)) cfg.onError(err);
            });
    };

    /**
     * Debounced AJAX fetch (e.g. on filter change).
     */
    ctx.ajaxDebounceFetch = () => {
        if (ajaxDebounce) clearTimeout(ajaxDebounce);
        ajaxDebounce = setTimeout(() => {
            ctx.ajaxPage = 1;
            ctx.ajaxFetch();
        }, AJAX_DEBOUNCE_MS);
    };

    /**
     * Navigate to a specific page.
     * @param {number} page
     */
    ctx.goToPage = (page) => {
        if (!ctx.ajax) return;
        ctx.ajaxPage = Math.max(1, Math.min(page, Math.ceil(ctx.ajaxTotal / ctx.ajax.pageSize)));
        ctx.ajaxFetch();
    };

    /**
     * Get current page info.
     * @returns {{ page, pageSize, total, totalPages }}
     */
    ctx.getPageInfo = () => {
        if (!ctx.ajax) return null;
        const pageSize = ctx.ajax.pageSize;
        return {
            page:       ctx.ajaxPage,
            pageSize:   pageSize,
            total:      ctx.ajaxTotal,
            totalPages: Math.ceil(ctx.ajaxTotal / pageSize),
        };
    };

    /**
     * Reload from AJAX source.
     */
    ctx.reload = () => ctx.ajaxFetch();

    // Cleanup
    ctx._paginationDestroy = () => {
        if (ajaxDebounce) clearTimeout(ajaxDebounce);
    };

    // Auto-fetch on install
    ctx.ajaxFetch();
}

export default installPagination;
